jsLib:
function deviceType() {
    let {
        java
    } = this;
    try {
        java.deviceID();
        return false;
    } catch (e) {
        try {
            java.androidId();
            return true;
        } catch (e) {
            return false;
        }
    }
}

function checkEnv() {
    let {
        java,
        source
    } = this;
    let isModified = false;
    try {
        new Packages.io.legato.kazusa.utils.TimeoutCancellationException('');
        isModified = true;
    } catch (e) {
        isModified = typeof source.loginUi == 'function' ? false : true;
    }

    try {
        java.put("is_modified_version", isModified ? "true" : "false");
    } catch (e) {}

    return isModified;
}

function isQRead() {
    let {
        java
    } = this;
    try {
        return java.qread && java.qread() == "1";
    } catch (e) {
        return false;
    }
}

function getServerHost() {
    let {
        source
    } = this;
    try {
        const config = JSON.parse(source.getVariable());
        return config?.[0]?.host || source.bookSourceUrl;
    } catch (e) {
        return source.bookSourceUrl;
    }
}

function getSessionId() {
    const {
        cookie,
        source
    } = this;
    try {
        let cookieHeader = String(cookie.getCookie('fanqienovel.com'));
        let sessionId = cookieHeader.match(/sessionid=([^;]+)/)?.[1] || null;
        if (sessionId) {
            return sessionId;
        }
    } catch (e) {}
    try {
        let loginInfo = source.getLoginInfoMap() || {};
        return loginInfo['番茄登录Token'] || "";
    } catch (e) {
        return "";
    }
}

function splitArray(input, size) {
    let output = []
    for (let i = 0; i < input.length; i += size) {
        output.push(input.slice(i, i + size))
    }
    return output
}

function getCommentIconColor() {
    let {
        source
    } = this;
    let color = "#666666";
    let loginInfo = source.getLoginInfoMap() || "";
    if (loginInfo['段评图标颜色'] && loginInfo['段评图标颜色'].startsWith('#')) {
        color = loginInfo['段评图标颜色'];
    }
    return color;
}

function wrapContentForIOS(content) {
    const pureContent = content.trim();
    if (deviceType.call(this)) {
        return pureContent;
    }
    let lines = pureContent.split('\n').map(line => {
        if (line.trim()) {
            const trimLine = line.trim().replace(/\s+/g, ' ');
            return `<span rs-native>${trimLine}</span>`;
        }
        return line;
    });
    return lines.join('\n');
}

function buildCommentUrl(sourceType, bid, cid, para) {
    let host = getServerHost.call(this);
    let isModifiedVersion = checkEnv.call(this);
    let aidParam = (!deviceType.call(this) || isQRead.call(this) || isModifiedVersion) ? "&aid=web" : "";

    switch (sourceType) {
        case 'jj':
            return host + '/jj_comment?bid=' + bid + '&cid=' + cid + '&para=' + para + aidParam;
        case 'qm':
            return host + '/qm_comment?item_id=' + cid + '&book_id=' + bid + '&paragraph_id=' + para + aidParam;
        case 'fq':
        default:
            return host + '/idea_comment?item_id=' + cid + '&book_id=' + bid + '&para=' + para + '&sessionid=' + getSessionId.call(this) + aidParam;
    }
}

function getCommentSourceName(sourceType) {
    switch (sourceType) {
        case 'jj':
            return '晋江';
        case 'qm':
            return '七猫';
        case 'fq':
        default:
            return '番茄';
    }
}

function startCommentBrowser(url, title) {
    let {
        java
    } = this;
    if (isQRead.call(this)) {
        java.startBrowserDp(url, title);
    } else {
        let isModifiedVersion = checkEnv.call(this);
        if (isModifiedVersion) {
            try {
                let htmlContent = java.ajax(url);
                java.showBrowser(
                    url,
                    htmlContent,
                    `window.java=java;`,
                    JSON.stringify({
                        "expandedCornersRadius": 20,
                        "dismissOnTouchOutside": true,
                        "isDraggable": true,
                        "shouldDimBackground": true,
                        "backgroundDimAmount": 0.5,
                        "hardwareAccelerated": true,
                        "isNestedScrollingEnabled": true,
                        "isGestureInsetBottomIgnored": true,
                        "setFitToContents": false,
                        "heightPercentage": 0.75,
                        "isHideable": true
                    })
                );
            } catch (e) {
                java.showBrowser(
                    url,
                    null,
                    `window.java=java;`,
                    JSON.stringify({
                        "expandedCornersRadius": 20,
                        "dismissOnTouchOutside": true,
                        "hardwareAccelerated": true,
                        "isNestedScrollingEnabled": true,
                        "isGestureInsetBottomIgnored": true,
                        "heightPercentage": 0.75,
                        "isHideable": true
                    })
                );
            }
        } else {
            java.startBrowser(url, title);
        }
    }
}

function createCommentHtmlTag(displayText, url, sourceName) {
    const encodedUrl = url.replace(/&/g, '&amp;');
    return '<comment count="' + displayText + '" onPress="java.' +
        (isQRead.call(this) ? 'startBrowserDp' : 'startBrowser') +
        '(\'' + encodedUrl + '\',\'' + sourceName + '段评\')" />';
}

function createSvg(number, color, bid, cid, para, sourceType = 'fq') {
    let {
        java
    } = this;
    var displayText = number > 99 ? "99+" : number;
    var date = String(Date.now()).match(/(\d{6}$)/)[1];

    let isIOS = !deviceType.call(this);
    if (isIOS) {
        let commentUrl = buildCommentUrl.call(this, sourceType, bid, cid, para);
        let sourceName = getCommentSourceName(sourceType);
        return createCommentHtmlTag.call(this, displayText, commentUrl, sourceName);
    }

    let isQingRead = isQRead.call(this);
    let isModifiedVersion = checkEnv.call(this);

    var svg;
    if (isQingRead || isModifiedVersion) {
        svg = '<svg width="160" height="120" xmlns="http://www.w3.org/2000/svg"><path d="M 55 10 L 120 10 Q 150 10 150 40 L 150 80 Q 150 110 120 110 L 55 110 Q 25 110 25 80 L 25 75 L 3 60 L 25 45 L 25 40 Q 25 10 55 10 Z" fill="none" stroke="' + color + '" stroke-width="5" stroke-linejoin="round"/><text x="87" y="77" font-family="Arial, sans-serif" text-anchor="middle" dominant-baseline="middle" font-size="50" font-weight="bold" fill="' + color + '">' + displayText + '</text></svg>';
    } else {
        svg = '<svg width="1000" height="909" xmlns="http://www.w3.org/2000/svg">' +
            '<path d="M80,80 h840 a60,60 0 0 1 60,60 v580 a60,60 0 0 1 -60,60 h-620 l-140,90 v-90 h-80 a60,60 0 0 1 -60,-60 v-580 a60,60 0 0 1 60,-60 z" ' +
            'fill="none" stroke="' + color + '" stroke-width="16" stroke-linejoin="round"/>' +
            '<text x="500" y="450" font-family="Arial, sans-serif" text-anchor="middle" ' +
            'font-size="360" fill="' + color + '" dy="0.3em">' + displayText + '</text>' +
            '</svg>';
    }

    var encodedSvg = java.base64Encode(svg);

    let jsFunction;
    switch (sourceType) {
        case 'jj':
            jsFunction = 'showJJCmt';
            break;
        case 'qm':
            jsFunction = 'showQmCmt';
            break;
        case 'fq':
        default:
            jsFunction = 'showCmt';
            break;
    }

    if (isModifiedVersion) {
        return 'data:image/svg+xml;base64,' + encodedSvg + ',{\'click\':\'' + jsFunction + '("' + bid + '","' + cid + '","' + para + '","' + date + '")\',\'style\':\'TEXT\'}';
    } else {
        return 'data:image/svg+xml;base64,' + encodedSvg + ',{\'js\':\'' + jsFunction + '("' + bid + '","' + cid + '","' + para + '","' + date + '")\',\'style\':\'TEXT\'}';
    }
}

function checkClickRateLimit(lastCallKey) {
    let {
        cache
    } = this;
    let lastCallTime = cache.getFromMemory(lastCallKey) || 0;
    let currentTime = Date.now();
    if (currentTime - lastCallTime < 1000) {
        return false;
    }
    cache.putMemory(lastCallKey, currentTime);
    return true;
}

function handleCommentClick(sourceType, bid, cid, para, date, cacheKey) {
    let {
        cache
    } = this;
    let isModifiedVersion = checkEnv.call(this);
    let isQingRead = isQRead.call(this);

    if (!isModifiedVersion && !isQingRead) {
        let mname = cacheKey;
        let load = (cache.getFromMemory(mname) ?? "-").split("-");
        if (load[0] != "1" || load[1] != date) {
            cache.putMemory(mname, "1-" + date);
            return;
        }
        let lastCallKey = `last_call_${sourceType}_${bid}_${cid}_${para}`;
        if (!checkClickRateLimit.call(this, lastCallKey)) {
            return;
        }
    }

    let commentUrl = buildCommentUrl.call(this, sourceType, bid, cid, para);
    let title = isModifiedVersion ? getCommentSourceName(sourceType) + "段评" : (cache.getFromMemory(cacheKey + "-text") ?? getCommentSourceName(sourceType) + "段评");
    startCommentBrowser.call(this, commentUrl, title);
}

function getComments(content, bid, cid, sourceType = 'fq', contentMd5 = null) {
    let {
        java,
        cache,
        source
    } = this;
    let host = getServerHost.call(this);
    try {
        let lines = String(content)
            .replace(new RegExp('(<img[^>]*?>)\n', 'g'), "$1")
            .split("\n")
            .filter(line => line.trim());

        let isModifiedVersion = checkEnv.call(this);
        let isQingRead = isQRead.call(this);

        if (sourceType == 'jj') {
            let apiUrl = `${host}/proxy_jjidea?bid=${bid}&cid=${cid}&token=${JJtoken.call(this)}`;
            let response = java.ajax(apiUrl);
            let data = JSON.parse(response).data;

            data.forEach((item) => {
                let para = item.paragraph_id;
                let count = item.comment_total;

                let paraNum = parseInt(para);
                if (paraNum <= 0 || paraNum > lines.length) {
                    return;
                }

                let adjustedPara = paraNum - 1;

                if (!isModifiedVersion && !isQingRead) {
                    cache.putMemory(`jj-${bid}-${cid}-${para}-text`, lines[adjustedPara]);
                }

                let color = getCommentIconColor.call(this);
                let commentTag = createSvg.call(this, count, color, bid, cid, para, sourceType);
                if (deviceType.call(this)) {
                    lines[adjustedPara] += `<img src="${commentTag}">`;
                } else {
                    lines[adjustedPara] += commentTag;
                }
            });
        } else if (sourceType == 'qm') {
            if (!contentMd5) return wrapContentForIOS.call(this, content);

            let apiUrl = `${host}/proxy_qmidea?action=paragraph_bubbles&book_id=${bid}&item_id=${cid}&content_md5=${contentMd5}`;
            let response = java.ajax(apiUrl);
            let data = JSON.parse(response).data;

            if (data.chapters && data.chapters.length > 0) {
                let chapterData = data.chapters[0];
                if (chapterData.bubbles) {
                    chapterData.bubbles.forEach((bubble, bubbleIndex) => {
                        let paraMd5 = bubble.p;
                        let count = parseInt(bubble.c) || 0;

                        if (count > 0 && bubbleIndex < lines.length) {
                            let paraIndex = bubbleIndex;

                            if (!isModifiedVersion && !isQingRead) {
                                cache.putMemory(`qm-${bid}-${cid}-${paraMd5}-text`, lines[paraIndex]);
                            }

                            let color = getCommentIconColor.call(this);
                            let commentTag = createSvg.call(this, count, color, bid, cid, paraMd5, sourceType);
                            if (deviceType.call(this)) {
                                lines[paraIndex] += `<img src="${commentTag}">`;
                            } else {
                                lines[paraIndex] += commentTag;
                            }
                        }
                    });
                }
            }
        } else {
            let apiUrl = `${host}/proxy_idea?item_id=${cid}`;
            let comments = java.ajax(apiUrl);
            let raw = JSON.parse(comments).data.data;

            Object.keys(raw).forEach((x) => {
                let lineIndex = parseInt(x);

                if (lineIndex >= lines.length || lineIndex < 0) {
                    return;
                }

                let lineContent = lines[lineIndex];

                let textOnly = String(lineContent)
                    .replace(new RegExp('<[^>]*>', 'g'), '')
                    .replace(/&nbsp;/g, ' ')
                    .trim();

                if (!textOnly) {
                    return;
                }

                if (!isModifiedVersion && !isQingRead) {
                    cache.putMemory(`fq-${bid}-${cid}-${x}-text`, textOnly || lineContent);
                }

                let color = getCommentIconColor.call(this);
                let commentTag = createSvg.call(this, raw[x].count, color, bid, cid, x, sourceType);
                if (deviceType.call(this)) {
                    lines[lineIndex] += `<img src="${commentTag}">`;
                } else {
                    lines[lineIndex] += commentTag;
                }
            });
        }

        let result = lines.join("\n");
        return wrapContentForIOS.call(this, result);
    } catch (e) {
        return wrapContentForIOS.call(this, content);
    }
}

function showJJCmt(bid, cid, para, date) {
    handleCommentClick.call(this, 'jj', bid, cid, para, date, `jj-${bid}-${cid}-${para}`);
}

function showCmt(bid, cid, para, date) {
    handleCommentClick.call(this, 'fq', bid, cid, para, date, `fq-${bid}-${cid}-${para}`);
}

function showQmCmt(bid, cid, para, date) {
    handleCommentClick.call(this, 'qm', bid, cid, para, date, `qm-${bid}-${cid}-${para}`);
}

function getSecretKey() {
    const {
        java,
        source
    } = this;
    try {
        let apiKey = "";
        const headerValue = source.getLoginHeader();
        if (headerValue && String(headerValue).length >= 10) {
            apiKey = String(headerValue);
        }
        if (!apiKey || apiKey.length < 10) {
            const storedKey = java.get("user_api_key");
            if (storedKey && String(storedKey).length >= 10) {
                apiKey = String(storedKey);
            }
        }
        if (!apiKey || apiKey.length < 10) {
            java.toast("❌ 未登录，请先登录");
            return "";
        }
        return java.base64Encode(apiKey);
    } catch (e) {
        java.toast("❌ 获取密钥失败");
        return "";
    }
}

function getSortKey() {
    let {
        java
    } = this;
    const sortKey = java.get("sortkey") || '';
    if (!sortKey) {
        java.toast("请先设置排序参数");
    }
    return sortKey;
}

function getBookIdFromUrl(baseUrl) {
    let {
        java,
        source
    } = this;
    let finalUrl;
    let urlMatch = baseUrl.match(/url=([^&]*)/);
    if (urlMatch && urlMatch[1]) {
        finalUrl = java.base64Decode(urlMatch[1]);
    } else {
        let fqurl = JSON.parse(java.base64Decode(baseUrl.split(",")[1]));
        finalUrl = java.base64Decode(fqurl.url);
    }
    let bookIdMatch = finalUrl.match(/book_id=(\d{19})/);
    return bookIdMatch ? bookIdMatch[1] : null;
}

function getBookData(bookId) {
    let {
        java,
        source
    } = this;
    let newUrl = "https://api5-normal-sinfonlineb.fqnovel.com/reading/bookapi/multi-detail/v/?aid=1967&iid=1&version_code=999&book_id=" + bookId;
    let response = java.ajax(newUrl);
    let responseData = JSON.parse(response);
    if (Array.isArray(responseData.data)) {
        return responseData.data[0];
    } else {
        return responseData.data;
    }
}

function parseAuthors(authorsData) {
    let {
        java,
        source
    } = this;
    let authors = [];
    try {
        authors = authorsData ? JSON.parse(authorsData) : [];
    } catch (e) {
        authors = authorsData ? authorsData.replace(/[\[\]"]/g, '').split(',') : [];
    }
    return authors.length > 0 ? (authors[0].AuthorName || authors[0] || "") : "";
}

function getToneInfo(bookId) {
    if (!bookId) return "";
    try {
        let tones = "\n===================\n🎧AI音色编号信息: ";
        let info = JSON.parse(java.ajax(`https://reading.snssdk.com/reading/bookapi/audio/toneinfo/?book_id=${bookId}&aid=1967`));
        for (let i of (info.data.tts_tones ? info.data.tts_tones : [])) {
            tones += `\n${i.id} - ${i.title}${i.description ? "(" + i.description + ")" : ""}`;
        }
        return tones;
    } catch (e) {
        return "";
    }
}

function syncReadingHistory(bookId) {
    let {
        java,
        source
    } = this;
    if (bookId) {
        var sessionid = getSessionId.call(this);
        if (sessionid && sessionid.trim() !== "") {
            var syncUrl = getServerHost.call(this) + "/update_history?book_id=" + bookId + "&sessionid=" + sessionid;
            java.ajax(syncUrl);
        }
    }
}

function getJjwxcNovelIdFromUrl(baseUrl) {
    let {
        java,
        source
    } = this;
    let finalUrl;
    try {
        let urlMatch = baseUrl.match(/url=([^&]*)/);
        if (urlMatch && urlMatch[1]) {
            finalUrl = java.base64Decode(urlMatch[1]);
        } else {
            let fqurl = JSON.parse(java.base64Decode(baseUrl.split(",")[1]));
            finalUrl = java.base64Decode(fqurl.url);
        }
        let novelIdMatch = finalUrl.match(/novelId=(\d+)/);
        if (novelIdMatch) {
            return novelIdMatch[1];
        }
    } catch (e) {}
    return null;
}

function buildChapterUrl(x, catalog, device) {
    let {
        java
    } = this;
    const isFanqieApp = ['番茄小说', '番茄短剧', '番茄听书', '番茄畅听'].includes(catalog.source);
    const urlToMatch = x.url || catalog.url;
    const bookId = urlToMatch.match(/book_id=(\d{19})\b/)?.[1] || null;
    const itemId = urlToMatch.match(/item_id=(\d+)/)?.[1] || null;
    let contentUrlParams = `chapter?cid=${x.cid}&source=${catalog.source}&device=${device}`;
    if (!isFanqieApp) {
        contentUrlParams += `&url=${catalog.url}`;
    } else {
        contentUrlParams += `&book_id=${bookId}&item_id=${itemId}`;
        if (['番茄听书', '番茄畅听'].includes(catalog.source)) {
            const toneId = Number((this.source.getLoginInfoMap())['听书AI音色编号']) || 1;
            contentUrlParams += `&tone_id=${toneId}`;
        }
    }
    if (catalog.source == '七猫') {
        const qmBookId = x.url.match(/book_id=(\d+)/)?.[1] || null;
        const qmChapterId = x.url.match(/item_id=(\d+)/)?.[1] || null;
        contentUrlParams += `&${x.url}`;
        if (qmBookId && qmChapterId) {
            const qmCommentUrl = `${getServerHost.call(this)}/qm_comment?book_id=${qmBookId}&item_id=${qmChapterId}`;
            return `data:contentUrl;base64,${java.base64Encode(contentUrlParams)},{"type":"qingci","js":"book ? result : '${qmCommentUrl}'"}`;
        } else {
            return `data:contentUrl;base64,${java.base64Encode(contentUrlParams)},{"type":"qingci"}`;
        }
    } else {
        let commentPart = '{"type":"qingci"}';
        if (catalog.source == '晋江') {
            const novelIdMatch = x.url.match(/novelId=(\d+)/);
            const chapterIdMatch = x.url.match(/chapterId=(\d+)/);
            if (novelIdMatch && chapterIdMatch) {
                const novelId = novelIdMatch[1];
                const chapterId = chapterIdMatch[1];
                const jjCommentUrl = `${getServerHost.call(this)}/jj_comment?novelId=${novelId}&chapterId=${chapterId}`;
                commentPart = `{"type":"qingci","js":"book ? result : '${jjCommentUrl}'"}`;
            }
        } else if (catalog.source == '番茄小说') {
            const fanqieCommentUrl = `${getServerHost.call(this)}/comment?sessionid=${getSessionId.call(this)}&item_id=${itemId}&book_id=${bookId}`;
            commentPart = `{"type":"qingci","js":"book ? result : '${fanqieCommentUrl}'"}`;
        } else if (catalog.source == '云端') {
            const decodedUrl = java.base64Decode(catalog.url);
            const commentUrl = decodedUrl.replace('share', 'comment');
            commentPart = `{"type":"qingci","js":"book ? result : '${commentUrl}&pt=3g'"}`;
        }
        return `data:contentUrl;base64,${java.base64Encode(contentUrlParams)},${commentPart}`;
    }
}

function showTabTips(catalog) {
    var tabTips = {
        audio: '听书',
        video: '视频',
        comic: '漫画'
    };
    if (tabTips[catalog.tab]) {
        this.java.toast('当前为' + tabTips[catalog.tab] + '模式');
    }
}

function buildSearchResult(key, sourceParam, host) {
    let {
        java
    } = this;
    if (key && key.length == 19 && !Number.isNaN(parseInt(key))) {
        return handleFanqieSearch.call(this, key, host);
    } else if (key && key.length == 7 && !Number.isNaN(parseInt(key))) {
        return handleJjwxcSearch.call(this, key, host);
    } else {
        return host + '/search?login=search&key={{key}}&page={{page}}' + sourceParam;
    }
}

function handleFanqieSearch(key, host) {
    let {
        java
    } = this;
    var u = host + `/detail?book_id=${key}`;
    var kdy = java.base64Encode(u);
    var response = JSON.parse(java.ajax(u));
    var nam = response.data.book_name || (response.data[0] && response.data[0].book_name) || '未知';
    return host + `/details?url=${kdy}&source=番茄小说&name=${encodeURIComponent(nam)}`;
}

function decode(data) {
    const {
        java
    } = this;
    const encryptedBytes = java.base64DecodeToByteArray(data);
    const crypto = java.createSymmetricCrypto("DES/CBC/PKCS5Padding", "K7bM2nXy", "tQ5v9rS1");
    return crypto.decryptStr(encryptedBytes);
}

