      },
      backup2: {
        name: '备用线路2',
        icon: 'satellite',
        baseUrl: 'https://20.langge.tk',
        downloadPath: '/sy/download/%E5%AE%89%E5%8D%93%E9%98%85%E8%AF%BBapp-%E5%A4%A7%E7%81%B0%E7%8B%BC%E8%9E%8D%E5%90%884.0(vip%E5%AE%8C%E5%85%A8%E7%89%88).json'
      },
      backup3: {
        name: '备用线路3',
        icon: 'link',
        baseUrl: 'http://219.154.201.122:5006',
        downloadPath: '/sy/download/%E5%AE%89%E5%8D%93%E9%98%85%E8%AF%BBapp-%E5%A4%A7%E7%81%B0%E7%8B%BC%E8%9E%8D%E5%90%884.0(vip%E5%AE%8C%E5%85%A8%E7%89%88).json'
      },
      backup4: {
        name: '备用线路4',
        icon: 'bolt',
        baseUrl: 'https://v2.czyl.cf',
        downloadPath: '/sy/download/%E5%AE%89%E5%8D%93%E9%98%85%E8%AF%BBapp-%E5%A4%A7%E7%81%B0%E7%8B%BC%E8%9E%8D%E5%90%884.0(vip%E5%AE%8C%E5%85%A8%E7%89%88).json'
      },
