function checkNet() {
    let url = getArgument('server');
    java.longToast(`\n\n♻️正在检测：${url}\n请稍等~`);
    let date1 = new Date().getTime();
    let html = java.ajax(url + '/login');
    let date2 = new Date().getTime();
    let t = date2 - date1;
    let c = String(html).indexOf('晴天');
    let code = 1;
    let time = t / 1000 + 's';
