function checkRss(){
	const {cache,java} = this;
	java.open("rss",null,null,"订阅源管理器");
	Packages.java.lang.Thread.sleep(1500);
  if(!cache.get("rssset")){
            let u = `legado://import/rssSource?src=http://www.yckceo.com/yuedu/rss/json/id/708.json`;
            java.openUrl(u)
      }
}


function getSource(url){
	const {java} = this;
	url = "legado://import?src="+encodeURIComponent(url);
	java.openUrl(url)
	}

function getRssSource(rssUrl){
	const {java,source} = this;
    try{
	let url = rssUrl+"/getRssSources";
	let rssData = JSON.parse(java.ajax(url)).data;
	let data = {};
	let webs = [];
	let groups = [];
	rssData.forEach(x=>{
  		let web = {};
          let index = x.name;
          let r = x;
          web.name = r.sourceName.replace(/\n/g,'');
          web.url = r.sourceUrl;
          web.group = (r.sourceGroup?r.sourceGroup.split(","):"") || ["-1"]

          web.group.forEach(groupItem => {
              if (!groups.some(group => group.id === groupItem)) {
                  groups.push({
                      id: groupItem,
                      s: 1,
                      name: groupItem!=="-1"?groupItem:"未分组"
                     });
                 }
           });
        webs.push(web);
    });
        if(!groups.find(x=>x.id==="-1"))
        groups.push({id:"-1",name:"未分组",s:1});
        groups.push({id:"-2",name:"全部",s:1})
        data.webs = webs;
        data.groups = groups;
        data.rssUrl = rssUrl;
        source.putVariable(JSON.stringify(data));
        java.refreshExplore();
        }catch(e){
            java.log(e)
        }
}

