  let text = el.text().trim();
  let match = text.match(/^(.+?)\s*\(ID:([\-\d\s]+)\)(\d+),(\d+)$/);
  if (!match) return null;
  let name = match[1].trim();
  let id = (match[2] || '').trim(); 
