       const data = java.ajax("https://爱国.asw3.cc/");
       Url = data.match(/id: '1'[\s\S]*?targetHref: '(https:\/\/[^']+)'/)[1];
       cache.put("Alice", Url, 60);
    }else {
       Url = lineUrl;
    }
    return Url;
}

