const ho = 'https://m.qidian.com'


function generateCsrfToken() {
 let jsmy = String(this.cookie.getCookie(ho).match(/_csrfToken=([^;]*)/)?.[1] || '');
return jsmy;
}

function qdtoken() {
let qdtoken = String(this.cookie.getCookie(ho));
return qdtoken;
}

