loginUrl:
function login() {
    try {
        let url = baseUrl.replace(/\/+$/, '').replace(/[^\w.:/-]/g, '');
        let ur = source.getLoginInfoMap();
        let params = `username=${ur.get("账号")}&password=${ur.get("密码")}`;
        let r = java.post(`${url}/api/login.php`, params, {});
        let resp = JSON.parse(r.body());
        if (resp.success) {
            let cookies = Array.from(r.cookies(), 
    ([k, v]) => `${k}=${v}`).join(';');
            return source.putLoginHeader(JSON.stringify({Cookie: cookies}));
        } else {
            throw new Error(`登录失败: ${resp.message || '未知错误'}`);
        }
    } catch (e) {
        java.log(`登录异常: ${e.message}\n请求参数: ${params}`);
    }
}

