        java.longToast('\n\n段评已关闭');
    } else {
        setArgument('fqpara', 'on');
        java.longToast("\n\n段评已开启\n\n长按刷新段后面的图片即可\n\n如果图片不显示，刷新无反应\n请更新测试版阅读app");
    }
}

// 强制搜索被禁用的源
function disabledSources() {
    var disabled_sources = getArgument('disabled_sources');
    if (disabled_sources == '1') {
        setArgument('disabled_sources', '0');
        java.longToast('\n\n强制搜索禁用的源已关闭');
    } else {
        setArgument('disabled_sources', '1');
        setArgument('source', '全部');
        java.longToast("\n\n强制搜索禁用的源已开启\n\n注意：开启后搜索时间会变长！");
    }
}

// 我要推荐
function put_book() {
    java.startBrowserAwait(getArgument('server') + '/put_book', '我来推荐');
}

