    }

    /* 按钮组 */
    .button-group {
      display: flex;
      flex-direction: column;
      gap: 10px;
      margin-bottom: 16px;
    }

    .button {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 10px;
      padding: 14px 28px;
      text-align: center;
      font-size: 1rem;
      border: none;
      border-radius: 12px;
      text-decoration: none;
      background: var(--primary-gradient);
      color: white;
      font-weight: 600;
      transition: all 0.3s ease;
      box-shadow: var(--shadow);
      position: relative;
      overflow: hidden;
      cursor: pointer;
    }

    .button i {
      font-size: 1rem;
    }

    .button::after {
      content: '';
      position: absolute;
      top: -50%;
      left: -50%;
      width: 200%;
      height: 200%;
      background: rgba(255, 255, 255, 0.1);
      transform: rotate(30deg);
      transition: all 0.6s ease;
      pointer-events: none;
    }

    .button:hover {
      transform: translateY(-3px);
      box-shadow: var(--shadow-hover);
    }

    .button:hover::after {
      transform: rotate(30deg) translate(20%, 20%);
    }

    .button:active {
      transform: scale(0.95);
    }

    /* 错误状态 */
    .error-state {
      text-align: center;
      padding: 40px 20px;
      color: var(--text-main);
    }

    .error-icon {
      font-size: 64px;
      margin-bottom: 20px;
      color: var(--error-color);
    }

    .error-text {
      font-size: 16px;
      line-height: 1.6;
      margin-bottom: 20px;
    }

    .retry-button {
      background: var(--primary-gradient);
      color: white;
      padding: 12px 30px;
      border-radius: 12px;
      border: none;
      font-weight: 600;
      cursor: pointer;
      transition: all 0.3s ease;
      font-size: 14px;
      box-shadow: var(--shadow);
    }

    .retry-button:hover {
      transform: translateY(-2px);
      box-shadow: var(--shadow-hover);
    }

    .retry-button:active {
      transform: scale(0.95);
    }

    /* 装饰元素 */
    .decoration {
      position: absolute;
      z-index: 0;
      pointer-events: none;
    }

    .decoration.circle {
      width: 120px;
      height: 120px;
      border-radius: 50%;
      background: rgba(107, 45, 216, 0.05);
      top: 10%;
      left: 10%;
    }

    .decoration.square {
      width: 80px;
      height: 80px;
      transform: rotate(45deg);
      background: rgba(78, 110, 242, 0.05);
      bottom: 10%;
      right: 10%;
    }

    /* 响应式 */
    @media (max-width: 768px) {
      body {
        padding: 12px;
      }

      .container {
        max-width: 100%;
        border-radius: 20px;
      }

      .header {
        padding: 20px 15px;
      }

      .header h1 {
        font-size: 1.3rem;
      }

      .header-icon {
        font-size: 40px;
      }

      .version-comparison {
        flex-direction: row;
        flex-wrap: nowrap;
        gap: 10px;
        padding: 12px;
        margin-top: 6px;
        overflow-x: auto;
      }

      .version-card {
        min-width: 45%;
        padding: 26px 12px 12px;
      }

      /* 移动端减弱呼吸动效 */
      .version-card.latest-version {
        animation: gradientAnimation 6s ease infinite;
      }

      .version-status {
        top: 5px;
        right: 5px;
        padding: 2px 5px;
        font-size: 0.6rem;
      }

      .version-number {
        font-size: 1.1rem;
      }

      .version-card.latest-version .version-number {
