let script = `setTimeout(function() {  
    let currentUrl = \`${currentUrl}\`;
    let contentJson = ${contentJson};
    let isLoading = false;
    let page = 1;
    let hasMore = true;
    loadUrl();

    function loadUrl(){
        let JsonData = getJson(contentJson);
        let html = createCommentHtml(JsonData);
        document.querySelector('.comments-container').innerHTML = html;
        openReply();
        window.scrollTo(0, 0);
    }

function getJson(jsonData,type){
    try{
        if(/^http/.test(jsonData)){
            jsonData = java.ajax(jsonData);
            jsonData = JSON.parse(jsonData || "{}");
        }
        JsonData = jsonData;
         if(type!==0)contentJson = jsonData;
        let data = JsonData?.data ?? {};
        let r = {};
        let commentList = [];
        let list = data.list;
        if(data.hotList && data.hotList.length>0){
            commentList.push({
                "title":"热门评论"
            });
            data.hotList.push({title:"最新评论"});
            list =  data.hotList.concat(list)
        }

        for(i in list){
            let x = list[i];
            let comment = {};
            if(x.title){
                commentList.push(x);
                continue;
            }
            comment.meta = java.timeFormat(x.publishTime)+"•"+(x.ipLocation??"");
            comment.content = x.content;
            comment.quote = (x.quote??"").replace(/^(.{12}).*/,'$1...');
            comment.quote = "${t}"=="1"?comment.quote:"";
            comment.authorFeedBack = x.authorFeedBack;
            comment.author = String(x.publisherBlogInfo.blogId) == "${blogid}"?"作者":"";
            comment.blogId = x.publisherBlogInfo.blogId;
            comment.emotes = x.emotes??[];
            comment.username = x.publisherBlogInfo.blogNickName;
            comment.l2Count = x.l2Count;
            comment.id = x.id;
            comment.agreenum = x.likeCount;
            comment.pics = x.images?x.images.map(x=>{return "<img src=\\""+x.orign+"\\">"}).join(""):"";
        commentList.push(comment)
    }

    if(type == 0)return commentList;
    r.list = commentList;
    return r
    }catch(e){
         return false
    }
}

  function replaceemotes(content,emotes){
      content = content.replace(/\\[图片\\]/g,'');
      emotes.forEach(x=>{
          let rex = x.name.replace(/([\\[\\]\\?\\$\\^\\(\\)])/g,"\\\\$1");
          let re = new RegExp(rex,'g');
          let pic = '<img class="ef" src="'+x.url+'">';
          content = content.replace(re,pic)
      });
      return content
  }

 function createCommentHtml(JsonData){
     if(JsonData && typeof JsonData!=="string"){
         html=createHtml(JsonData.list,"comment");
         return html;
     }else{
        java.longToast("错误");
        const loader = document.createElement('div');
        loader.className = 'loading-more';
        loader.style.cssText = \`
        text-align: center;
        padding: 10px;
        color: #666;
        font-size: 14px;
    \`;
    loader.textContent = typeof JsonData==="string"?JsonData:"加载失败，点击重试"
    loader.style.color = '#f00';
    return loader.outerHTML
    }
}
document.addEventListener('click', function(e) {
  if (e.target.classList.contains('username')) {
    const readerId = e.target.dataset.id;
    addShelf(readerId);
  }
});


function openReply(){
document.querySelectorAll('.load-more-replies,.close-more-replies').forEach(btn => {
            btn.addEventListener('click', function(e) {
                   let className = this.className;
                   if(/load-more-replies/.test(className)){
                         const repliesSection = e.target.parentNode;
                         let content = this.textContent;
                         let dataid = this.dataset.id;
                         let totalnum = Number(content.match(/共(\\d+)/)[1]);
                         let datanum = Number(this.dataset.num);
                         if(datanum<totalnum){
                             let replyapi = \`https://api.lofter.com/comment/l2/page/abtest.json?postId=${postid}&blogId=${blogid}&id=$\{dataid}&offset=$\{datanum}&fromSrc=&fromId=\`;
                             this.insertAdjacentHTML('beforebegin', createHtml(getJson(replyapi,0),"reply",1));
                             this.dataset.num = datanum+5;
                             let synum = Number(content.match(/还剩(\\d+)/)[1])-5;
                             if(synum>0){
                                 this.textContent = content.replace(/还剩\\d+/,'还剩'+synum)
                              }else{
                                  this.classList.add("hide");
                               }
                         }
                   }
            });
        });
    }


function addShelf(id){
    try{
   let authoru = \`http://api.lofter.com/v2.0/blogHomePage.api?product=lofter-android-7.4.4,{"method": "POST","body":"targetblogid=$\{id}&method=getBlogInfoDetail&returnData=1&limit=2000&offset=0&&checkpwd=1&needgetpoststat=1"}\`;

