function getArguments(open_argument, key) {
    try {
        open_argument = JSON.parse(open_argument);
    } catch (e) {
        open_argument = {
            tab: "小说",
            tone_id: "默认音色",
            server: host[0],
            sources: "全部",
            source_type: "男频",
        };
    }
    if (key) {
        return open_argument[key];
    } else {
        return open_argument;
    }
}

function setArguments(key, value) {
    const {
        source
    } = this;
    let open_argument = source.getVariable();
    open_argument = getArguments(open_argument, '');
    open_argument[key] = value;
    open_argument = JSON.stringify(open_argument);
    source.setVariable(open_argument);
    return open_argument;
}

function decrypt(Text) {
    return Text;
}

function paraForAndroid(content, sources, ydv) {
    let {
        java,
        cache,
        source
    } = this;
    let plcolor = getArguments(source.getVariable(), "plcolor");
    if (!plcolor) {
        plcolor = "#A9A9A9";
    }
    let tccolor = getArguments(source.getVariable(), "tccolor");
    if (!tccolor) {
        tccolor = "#ffffff";
    }

    const createSvg = this.createSvg.bind(this);

    return content.replace(/<p>(.*?)(?:<comment ident="([^"]*)" count="([^"]*)" \/>)?<\/p>/g,
        (match, text, url, count) => {
            if (url && count) {
                const click = 0;
                cache.putMemory(url, click);
                const encodedUrl = url;
                return `<p>${text}<img src="${createSvg(count, plcolor,tccolor,encodedUrl,sources,ydv)}"></p>`;
            } else {
                return `<p>${text}</p>`;
            }
        }
    );
}


function showCmt(url, sources, ydv) {
    let {
        java,
        cache
    } = this;
    const currentTime = Date.now();
    const click = cache.getFromMemory(url);
    let isqread = false;
    try {
        java.qread();
        isqread = true;
    } catch (e) {}
    if (click < 1 && !isqread && !ydv) {
        cache.putMemory(url, click + 1);
        return;
    } else {
        if (isqread) {
            java.startBrowserDp(url, sources + '段评');
        } else if (ydv) {
            let paradata = new Date().toLocaleDateString();
            let htmlContent = cache.get(paradata);
            if (!htmlContent || String(htmlContent).indexOf("评论") == -1) {
                java.longToast(`\n${paradata} 初始化段评页面,请稍等~`);
                try {
                    htmlContent = java.ajax(url);
                } catch {
                    htmlContent = paraHtml(url);
                }

                cache.put(paradata, htmlContent);
                java.longToast(`\n${paradata} 初始化段评页面成功~`);
            }
            java.showBrowser(
                url,
                htmlContent,
                `window.java=java;`,
                JSON.stringify({
                    "expandedCornersRadius": 20,
                    "dismissOnTouchOutside": true,
                    "isDraggable": true,
                    "shouldDimBackground": true,
                    "backgroundDimAmount": 0.5,
                    "hardwareAccelerated": true,
                    "isNestedScrollingEnabled": true,
                    "isGestureInsetBottomIgnored": true,
                    "setFitToContents": true,
                    "isHideable": true,
                    "heightPercentage": 0.8
                })
            );
        } else {
            java.startBrowser(url, sources + '段评');
        }
    }
}



function createSvg(number, color, tccolor, encodedUrl, sources, ydv) {
    var displayText = number > 99 ? "99+" : number.toString();
    var loginInfoMap = {};

    if (this.source && typeof this.source.getLoginInfoMap == 'function') {
        loginInfoMap = this.source.getLoginInfoMap() || {};
    }

    var bubbleStyle = String(getArguments(this.source.getVariable(), "pstyle") || loginInfoMap['段评气泡样式(0-4)'] || '0');
    var svg;
    if (bubbleStyle == '0') {
