        /* 评论弹窗 */
        .modal-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0, 0, 0, 0.5);
            z-index: 200;
            display: none;
            align-items: flex-start;
            justify-content: center;
            overflow: hidden;
            padding-top: 180px;
        }

        .modal-overlay.show {
            display: flex;
        }

        .modal-content {
            background: #fff;
            width: 90%;
            max-width: 500px;
            border-radius: 16px;
            padding: 20px;
            animation: slideDown 0.3s ease;
            transition: transform 0.3s ease;
            max-height: 80vh;
            box-shadow: 0 10px 40px rgba(0,0,0,0.2);
        }

        @keyframes slideDown {
            from {
                transform: translateY(-100%);
            }
            to {
                transform: translateY(0);
            }
        }

        .modal-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            margin-bottom: 16px;
        }

        .modal-title {
            font-size: 16px;
            font-weight: 600;
        }

        .modal-close {
            font-size: 24px;
            color: #999;
            cursor: pointer;
            padding: 4px;
        }

        .modal-textarea-wrapper {
            position: relative;
            margin-bottom: 12px;
        }

        .modal-textarea {
            width: 100%;
            min-height: 120px;
            border: 1px solid #eee;
            border-radius: 8px;
            padding: 12px;
            padding-bottom: 40px;
            font-size: 15px;
            resize: none;
            outline: none;
        }

        .modal-textarea:focus {
            border-color: #07c160;
        }

        .emoji-toggle-btn {
            position: absolute;
            bottom: 10px;
            right: 10px;
            font-size: 22px;
            color: #999;
            cursor: pointer;
            background: none;
            border: none;
            padding: 4px;
            transition: color 0.2s;
        }

        .emoji-toggle-btn:hover {
            color: #07c160;
        }

        /* 表情面板 */
        .emoji-panel {
            position: absolute;
            bottom: 45px;
            right: 0;
            background: #fff;
            border: 1px solid #eee;
            border-radius: 8px;
            box-shadow: 0 4px 20px rgba(0,0,0,0.15);
            padding: 12px;
            width: 320px;
            max-height: 280px;
            overflow-y: auto;
            z-index: 10;
            display: none;
        }

        .emoji-panel.show {
            display: block;
        }

        .emoji-grid {
            display: grid;
            grid-template-columns: repeat(6, 1fr);
            gap: 6px;
        }

        .emoji-btn {
            padding: 8px;
            border: none;
            background: transparent;
            cursor: pointer;
            border-radius: 6px;
            transition: background 0.2s;
            display: flex;
            align-items: center;
            justify-content: center;
            aspect-ratio: 1;
        }

        .emoji-btn:hover {
            background: #f0f0f0;
        }

        .emoji-btn img {
            width: 24px;
            height: 24px;
        }

        .modal-footer {
            display: flex;
            align-items: center;
            justify-content: space-between;
        }

        .char-count {
            font-size: 13px;
            color: #999;
        }

        .char-count.over {
            color: #ff4d4f;
        }

        .submit-btn {
            background: #07c160;
            color: #fff;
            border: none;
            padding: 8px 24px;
            border-radius: 20px;
            font-size: 14px;
            font-weight: 500;
            cursor: pointer;
        }

        .submit-btn:disabled {
            background: #ccc;
            cursor: not-allowed;
        }

        /* 图片预览 */
        .image-preview {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0, 0, 0, 0.9);
            z-index: 300;
            display: none;
            align-items: center;
            justify-content: center;
        }

        .image-preview.show {
            display: flex;
        }

        .image-preview img {
            max-width: 90%;
            max-height: 90%;
            border-radius: 8px;
        }

        .image-preview-close {
            position: absolute;
            top: 20px;
            right: 20px;
            font-size: 32px;
            color: #fff;
            cursor: pointer;
        }

        /* Toast */
        .toast {
            position: fixed;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            background: rgba(0, 0, 0, 0.75);
            color: #fff;
            padding: 12px 24px;
            border-radius: 8px;
            font-size: 14px;
            z-index: 400;
            display: none;
        }

        .toast.show {
            display: block;
        }

        /* 隐藏 */
        .hidden {
            display: none !important;
        }

        /* 深色模式 */
        html.dark, body.dark {
            background: #1a1a1a;
            color: #e0e0e0;
        }

        /* 确保在深色模式下整个页面都是深色背景 */
        .dark {
            background: #1a1a1a;
        }

        .dark .header {
            background: #2d2d2d;
            border-bottom-color: #3d3d3d;
        }

        .dark .header-title {
            color: #e0e0e0;
        }

        .dark .header-back {
            color: #999;
        }

        .dark .sort-btn {
            background: #3d3d3d;
            color: #999;
        }

        .dark .sort-btn:hover:not(.active) {
            background: #4d4d4d;
        }

        .dark .sort-btn.active {
            background: #07c160;
            color: #fff;
        }

        .dark .comment-btn {
            background: transparent;
            color: #07c160;
            box-shadow: none;
        }

        .dark .comment-btn:hover {
            background: transparent;
            color: #05a850;
            box-shadow: none;
        }

        .dark .comment-btn:active {
            background: transparent;
            box-shadow: none;
        }

        .dark .paragraph-quote {
            background: #2d2d2d;
            color: #aaa;
        }

        .dark .comment-list {
            background: #2d2d2d;
        }

        .dark .comment-item {
            border-bottom-color: #3d3d3d;
        }

        .dark .comment-username {
            color: #e0e0e0;
        }

        .dark .comment-content {
            color: #ccc;
        }

        .dark .comment-time {
