            background: #3d3d3d;
        }

        .dark .input-wrapper span {
            color: #777;
        }

        .dark .bottom-action-btn {
            color: #999;
        }

        .dark .modal-content {
            background: #2d2d2d;
        }

        .dark .modal-title {
            color: #e0e0e0;
        }

        .dark .modal-textarea {
            background: #3d3d3d;
            border-color: #4d4d4d;
            color: #e0e0e0;
        }

        .dark .modal-textarea:focus {
            border-color: #07c160;
        }

        .dark .emoji-panel {
            background: #2d2d2d;
            border-color: #4d4d4d;
        }

        .dark .emoji-btn:hover {
            background: #3d3d3d;
        }

        .dark .section-title {
            color: #e0e0e0;
        }

        .dark .loading {
            color: #777;
        }

        .dark .loading-spinner {
            border-color: #3d3d3d;
