        }

        .dark .empty {
            color: #666;
        }

        .dark .empty-title {
            color: #999;
        }

        .dark .no-more {
            color: #666;
        }

        .dark .default-avatar {
            background: linear-gradient(135deg, #4a5568 0%, #2d3748 100%);
        }

        /* 深色模式切换按钮 */
        .theme-toggle {
            width: 36px;
            height: 36px;
            border-radius: 50%;
            border: none;
            background: #f5f5f5;
            color: #666;
            font-size: 16px;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            margin-left: 12px;
        }

        .theme-toggle:hover {
            background: #eee;
        }

        .dark .theme-toggle {
            background: #3d3d3d;
            color: #ffc107;
        }

        .dark .theme-toggle:hover {
            background: #4d4d4d;
        }

        /* ==================== PC端响应式优化 ==================== */
        @media (min-width: 768px) {
            body {
                background: #e8e8e8;
            }

            .dark body,
            body.dark {
                background: #121212;
            }

            .header {
                max-width: 800px;
                left: 50%;
                transform: translateX(-50%);
                border-radius: 0 0 12px 12px;
                box-shadow: 0 2px 12px rgba(0,0,0,0.08);
            }

            .main-container {
                max-width: 800px;
                margin: 0 auto;
                padding-top: 72px;
                background: transparent;
            }

            .paragraph-quote {
                margin: 16px 0;
                border-radius: 12px;
                box-shadow: 0 2px 8px rgba(0,0,0,0.04);
            }

            .hot-section {
                margin: 16px 0;
            }

            .comment-list {
                border-radius: 12px;
                box-shadow: 0 2px 8px rgba(0,0,0,0.04);
            }

            .comment-item {
                padding: 20px 24px;
            }

            .comment-item:hover {
                background: #fafafa;
            }

            .dark .comment-item:hover {
                background: #363636;
            }

            .comment-avatar img,
            .default-avatar {
                width: 48px;
                height: 48px;
                font-size: 20px;
            }

            .comment-main {
                gap: 16px;
            }

            .comment-username {
                font-size: 15px;
            }

            .comment-content {
                font-size: 15px;
                line-height: 1.7;
            }

            .comment-image {
                max-width: 300px;
                max-height: 300px;
            }

            .expand-replies {
                padding-left: 64px;
            }

            .reply-list {
                padding-left: 64px;
            }

            .reply-avatar img,
            .default-avatar.small {
                width: 32px;
                height: 32px;
                font-size: 14px;
            }

            .reply-main {
                gap: 12px;
            }

            .reply-username {
                font-size: 14px;
            }

            .reply-content {
                font-size: 14px;
                line-height: 1.6;
            }

            .bottom-bar {
                max-width: 800px;
                left: 50%;
                transform: translateX(-50%);
                border-radius: 12px 12px 0 0;
                box-shadow: 0 -2px 12px rgba(0,0,0,0.08);
            }

            .modal-content {
                max-width: 600px;
                margin: 0 auto;
                border-radius: 16px;
                margin-bottom: 20px;
            }

            /* 更多评论区域 */
            #moreSection {
                margin: 16px 0;
            }

            /* 加载状态 */
            .loading,
            .empty {
                background: #fff;
                border-radius: 12px;
                margin: 16px 0;
            }

            .dark .loading,
            .dark .empty {
                background: #2d2d2d;
            }

            .no-more {
                padding: 30px;
            }

            /* 列表容器 */
            .main-container > div[style*="margin: 0 12px"] {
                margin: 0 !important;
            }
