function getJson(url,t,upmid){
    let commentList = [];
    let r = {};
    let allReplys = [];
    if(t==1){
        allReplys  = url;
    }else{
        let data = String(java.ajax(url));
        let JsonData = JSON.parse(data || "{}");
        data = JsonData.data;
        upmid = data.upper.mid;
        if(t!==2)
        offset = data.cursor.pagination_reply.next_offset;


        if(data.root && replyPage ==1){
            data.top_replies = [];
            data.root.rcount = 0;
            pageTotal = data.page.count;
            data.top_replies.push(data.root)
        }

        r.commentTotal = data?.cursor?.all_count;
        allReplys = data.top_replies?data.top_replies.concat(data.replies):data.replies;
    }


    for(i in allReplys){
        let x = allReplys[i];
        let comment = {};

        comment.meta =  x.reply_control.time_desc+(x.reply_control.up_reply?"•UP主回复":"");

        comment.content = parseContent(x.content.message,x.content.pictures,x.content.emote,x.content.at_name_to_mid,x.content.jump_url);
        comment.username = x.member.uname;
        comment.agreenum = x.like;
        let top = x.reply_control.is_up_top?"置顶":""
        if(top)comment.top = top;
        comment.authorid = upmid;
        comment.isAuthor = x.member.mid==upmid;
        comment.readerid = x.member.mid;
        comment.icon = x.member.nameplate.image ?? "";
        comment.rate = "LV"+x.member.level_info.current_level;
        comment.replyNum = Number(x.rcount) ?? 0;
        comment.id = x.rpid;
        comment.author_agree= x.reply_control.up_like;
        if(comment.replyNum>0){
            comment.list = x.replies?getJson(x.replies,1,upmid):[];
        }
        commentList.push(comment)
    }

    if(t==1)return commentList;

    r.list = commentList;
    return r

}     

 function parseContent(content,pics,emo,atname,jump_url){
     if(emo){
         let emok = Object.keys(emo)
         let emok2 = emok.map(key => 
                   key.replace(/[.*+?^$\{}()|[\\]\\\\]/g, '\\\\$&')
         );
         emok2.forEach((x,i)=>{
             let re = new RegExp(x,'g');
            content = content.replace(re,"<img src=\\""+emo[emok[i]].url+"\\" class=\\"emote\\">")
         })
      }

      if(atname){
          let atnamek = Object.keys(atname);
          let atname2 = atnamek.map(key => 
                   key.replace(/[.*+?^$\{}()|[\\]\\\\]/g, '\\\\$&')
         );

         atname2.forEach((x,i)=>{
             let re = new RegExp("@"+x,'g');
            content = content.replace(re,"<span class=\\"atname\\" data-readerid=\\""+atname[atnamek[i]]+"\\">@"+atnamek[i]+"</span>")
         })
      }


      if(jump_url){
          let jump_urlk = Object.keys(jump_url);
          let jump_url2 = jump_urlk.map(key => 
                   key.replace(/[.*+?^$\{}()|[\\]\\\\]/g, '\\\\$&')
         );

         jump_url2.forEach((x,i)=>{
             let re = new RegExp(x,'g');
             let aid =/^\\d+$/.test(jump_url[jump_urlk[i]].click_report)?jump_url[jump_urlk[i]].click_report:jump_urlk[i];
             let type = /^\\d+$/.test(aid)?"🎥":(/^http/.test(aid)?"🔗":"🔎");
            content = content.replace(re,"<span class=\\"jump_url\\" data-aid=\\""+aid+"\\">"+type+jump_url[jump_urlk[i]].title+"</span>")
         })
      }
    let imgs = "";

    if(pics && pics.length > 0){
    pics.forEach((x, index) => {
        imgs += \`<div class="picture-item">
            <div class="loading-spinner">加载中...</div>
            <img src="$\{x.img_src}" 
                 loading="lazy"
                 class="picture"
                 onload="this.parentNode.querySelector('.loading-spinner').style.display='none'"
                 onerror="this.parentNode.querySelector('.loading-spinner').style.display='none'; this.style.display='none'"
                 alt="图片$\{index + 1}">
        </div>\`;
    });

    imgs = \`<div class="picture-grid">$\{imgs}</div>\`;
}

     return content.replace(/\\n/g,'<br>')+imgs

 }

 function createCommentHtml(JsonData){
