function createHtml(JsonData,t,type){
    let html = "";
    for(i in JsonData){
        let x = JsonData[i];
        let replyHtml = "";

        if(x.replyNum>0){
            let openReply ="";
               openReply = \` <div class="load-more-replies" data-id="$\{x.id}" data-num="$\{x.replyNum}">
                  <i class="fa fa-angle-double-down"></i> 共$\{x.replyNum}条回复</div>\`

            replyHtml = \`<div class="replies-section">
                $\{createHtml(x.list,"reply")}
                $\{openReply}
            </div>\`
        }
        let user_badges = "";
        if(x.top){
            user_badges = \`<div class="user-badges">
                    <div class="badge primary">$\{x.top}</div>
                </div>\`
        }else if(x.icon || x.rate){
              user_badges = \`<div class="user-badges">
                    <div class="badge gold">
                          <img src="$\{x.icon}">$\{x.rate}
                    </div>
                </div>\`
        }
        let info = "";
        if(x.agreenum>=0){
            info = \`<div class="comment-info">
                        <div class="comment-meta">$\{x.meta.replace(/•$/,'')}</div>
                        <div class="comment-actions">
                            <div class="action-btn"><i class="far fa-thumbs-up"></i> $\{x.agreenum}</div>
                       </div>
                    </div>\`
        }
        let author_agree="";
        if(x.author_agree){
             author_agree =\`<div class="like" style="flex:1;text-align:right"><div class="badge" style="background:#E9F3EE;color:#6CAB8D;display:inline-block;">UP主点赞</div></div>\`
        }
        html+=\`<div class="$\{t}-item$\{type?' reply-add':''}">
                    <div class="$\{t}-header">
                         <div class="username" data-readerid="$\{x.readerid}">$\{x.username}</div>
                        $\{x.isAuthor==1?'<div class="reply-label">UP主</div>':''}
                        $\{user_badges}
                        $\{author_agree}
                    </div>
                    <div class="comment-content">$\{x.content}</div>
                    $\{info}
                    $\{replyHtml}
                </div>\`
    };
    if(t=="comment"){
        if(html==""){
            html = \`    <div style="text-align: center;
        padding: 10px;
        color: #666;
        font-size: 14px;">暂无评论</div>\`
        }
    }
    return html
}

function checkScrollBottom() {
    if (isLoading || !hasMore) return;
    const lastComment = document.querySelector('.comment-item:last-of-type');
    if (!lastComment) return;
    const windowHeight = window.innerHeight;
    const documentHeight = document.documentElement.scrollHeight;
    const scrollTop = window.scrollY || document.documentElement.scrollTop;
    if (documentHeight - (scrollTop + windowHeight) < 100) {
        loadNextPage();
    }
}


function loadNextPage(t) {
    if(t){
        if (isReplyLoading || !hasReplyMore) return;
        replyPage++;
    }else{
        if (isLoading || !hasMore) return;
        page++;
    }
    if (offset == undefined || replyPage > Math.ceil((pageTotal/20))) { 
                hasMore = false;
                const noMore = document.createElement('div');
                noMore.className = 'no-more';
                noMore.textContent = '没有更多评论了';
                noMore.style.cssText = \`
                    text-align: center;
                    padding: 10px;
                    color: #999;
                    font-size: 14px;
                \`;
                 let container2 =   t ? document.querySelector(".reply-content") : document.querySelector('.comments-container') ;
                container2?.appendChild(noMore);
                container2.scrollTop = container2.scrollHeight - container2.clientHeight;

                return;
    }


    t ? isReplyLoading = true : isLoading = true;
    const loader = document.createElement('div');
    loader.className = 'loading-more';
    loader.textContent = '加载 第'+(t?replyPage:page)+'页 中...';
    loader.style.cssText = \`
        text-align: center;
        padding: 10px;
        color: #666;
        font-size: 14px;
    \`;

    const container = t ? document.querySelector(".reply-content") : document.querySelector('.comments-container') ;
    container.appendChild(loader);
    container.scrollTop = container.scrollHeight - container.clientHeight;

    setTimeout(() => {
        fetchMoreComments(t)
            .then(() => {
                container.removeChild(loader);
                t?isReplyLoading = false: isLoading = false;

            })
            .catch(() => {
                loader.textContent = '加载失败，点击重试';
                loader.style.color = '#f00';
                loader.onclick = () => {
                    container.removeChild(loader);
                    if(t){
                        isReplyLoading = false;
                        replyPage--
                    }else{
                        isLoading = false;
                        page--;
                     }

                   t?null: loadUrl();
                };
            });
    }, 100);
}

