function getValueByIconAndName(icon, filterType, optionName, typeName) {
  let targetType = typeName;

  if (!targetType && icon) {
    let iconIndex = fenlei.图标.indexOf(icon);
    if (iconIndex === -1) {

      return -1;
    }
    targetType = fenlei.类型[iconIndex];
  } else if (!targetType) {
    return -1;
  }

  if (!fenlei[filterType]) {
    return -1;
  }

  let filterData = fenlei[filterType];

  if (Array.isArray(filterData)) {
    let option = filterData.find(item => item.n === optionName);
    return option ? option.v : -1;
  }

  if (typeof filterData === 'object') {
    if (filterData[targetType]) {
      let typeData = filterData[targetType];
      if (Array.isArray(typeData) && typeData[0] === -1) {
        for (let i = 1; i < typeData.length; i++) {
          if (typeData[i].n === optionName) {
            return typeData[i].v;
          }
        }
      } 
      else if (Array.isArray(typeData)) {
        let option = typeData.find(item => item.n === optionName);
        if (option) {
          return option.v;
        }
      }
    }

    for (let type in filterData) {
      if (type !== targetType) {
        let typeData = filterData[type];

        if (Array.isArray(typeData)) {
          if (typeData[0] === -1) {
            for (let i = 1; i < typeData.length; i++) {
              if (typeData[i].n === optionName) {
                return typeData[i].v;
              }
            }
          } else {
            let option = typeData.find(item => item.n === optionName);
            if (option) {
              return option.v;
            }
          }
        }
      }
    }
  }


  return -1;
}

