function getNodes(nodes){
	  const {java} = this;
	  let text = "";
      let js;
      nodes.pics?nodes.pics.forEach(pic=>{
          text += `<img src="${pic.url}">`
      }):null;
    nodes[0]?nodes.forEach(node=>{
        switch(node.type || node.node_type){
            case 1:
            case "TEXT_NODE_TYPE_WORD":
                text += node.word.words;
            break;

            case 2:
            case "TEXT_NODE_TYPE_RICH":
                let rich = node.rich;
                switch(rich.type){
                    case "RICH_TEXT_NODE_TYPE_TEXT":
                        text += rich.text;
                    break;

                   case "RICH_TEXT_NODE_TYPE_AT":
                       text+=`${this.getClickImg("user",rich.rid)}${rich.text.replace(/^@/,'')}`;
                    break;

                    case "RICH_TEXT_NODE_TYPE_OGV_EP":
                    case "RICH_TEXT_NODE_TYPE_OGV_SEASON":
                    case "RICH_TEXT_NODE_TYPE_AV":
                    case "RICH_TEXT_NODE_TYPE_BV":
                        text+=`\n${this.getClickImg("video",rich.rid)}${rich.text}\n`;
                    break;

                    case "RICH_TEXT_NODE_TYPE_CV":
                        text+=`${this.getClickImg("article",rich.rid)}${rich.text}`;
                    break;

                    case "RICH_TEXT_NODE_TYPE_EMOJI":
                        text += `<img src="${rich.emoji.icon_url},{style:\"text\"}">`;
                    break;

                    case "RICH_TEXT_NODE_TYPE_VIEW_PICTURE":
                        let pics = rich.pics;
                        pics.forEach(pic=>{
                            text += `<img src="${pic.src}">`
                        })
                    break;

                    case "RICH_TEXT_NODE_TYPE_WEB":
                        text+=`${this.getClickImg("link",rich.jump_url)}${rich.text}`;
                    break;

                    default:
                        text += rich?.text??""
                    break;
                }
            break;
         }
     }):""
    return text	
}

function getLinkCard(data){
    const {java} = this;
    let html = "";
    let d,title,cover,desc,desc1,desc2,url;
    let type = data.type;
    switch(type){
        //视频
        case "ADDITIONAL_TYPE_UGC":
        case "LINK_CARD_TYPE_UGC":
            d = data.ugc;
            title = `${this.getClickImg("video",d.id_str)}${d.title}\n`;
            cover =  `${this.getClickImg("video",d.id_str,d.cover,1)}\n`;
            let duration = "时长："+d.duration;
            let play = d.desc_second;
            html += title+cover+duration+"  "+play
            break;

        case "ADDITIONAL_TYPE_COMMON":
        case "LINK_CARD_TYPE_COMMON":
            d = data.common;
            title = d.title;
            desc1 = d.desc1;
            desc2 = d.desc2;
            url = d.jump_url
            cover = `${this.getClickImg("link",url,d.cover,2)}\n`;
            html += title+cover+desc1+"\n"+desc2
        break;

        case "ADDITIONAL_TYPE_RESERVE":
        case "LINK_CARD_TYPE_RESERVE":
            d = data.reserve;
            title = d.title;
            desc1 = d.desc1.text;
            let status = d.button.status;
            let t = d.button.type;
            let button;

            if(status == 1){
                button = d.button?.uncheck?.text
            }else{
                button = d.button?.check?.text
            }
            if(t == 1){
                button = d.button.jump_style.text;
            }
            let svg = `<svg width="180" height="80" xmlns="http://www.w3.org/2000/svg"><rect x="1" y="1" width="178" height="78" rx="4" fill="#50B4E5" stroke="#fff" stroke-width="0.5"/><text x="${178/2}" y="${78/2+12}" text-anchor="middle"  dominant-baseline="middle" font-family="Arial, sans-serif" font-size="35" font-weight="bold" fill="#fff">${button}</text></svg>`;
            svg = 'data:image/svg+xml;base64,' + java.base64Encode(svg);
            if(t == 1){
                cover = this.getClickImg("link",d.button.jump_url,svg,2)
            }else{
                cover = this.getClickImg("user",d.up_mid,svg,2)
            }

            html += cover+"\n"+title+"\n"+desc1
            break

        case "LINK_CARD_TYPE_OPUS":
            //未找到测试样本
            return type+"未找到本测试样本，如果你看到这个信息，请把这个详情页链接给我"
            break;

        case "LINK_CARD_TYPE_ITEM_NULL":
            return data..item_null.text

        default:
           html = ""

    }
    return html?"\n————————\n"+html:html
}

